mapper.select:
SELECT * FROM ( SELECT trip_conts_id AS tripContsId, trip_nm AS tripNm, trip_path_nm AS tripPathNm, trip_addr AS tripAddr, trip_tag AS tripTag FROM TRIP
trip_path_nm IS NOT NULL
/* 연령대 태그가 있는 것 우선 */ AND trip_tag LIKE '%' || #{userAgeGroup} || '%'
/* 태그가 없으면 일반 관광지(12), 문화시설(14) 등에서 랜덤 */ AND trip_clsf IN ('12', '14', '28')
ORDER BY DBMS_RANDOM.VALUE ) WHERE ROWNUM <= 4

mapper.delete:
DELETE FROM relation
WHERE USER_NO = #{userNo}
AND TRIP_CONTS_ID = #{tripContsId}
AND REL_CLSF = #{relClsf}
